**Backend Implementation (src/server.js):**
1. Import WebSocket at top (after line 8): `import { WebSocketServer } from 'ws';`
2. In `createServer()` function (line ~60), after `const app = express();`, add:
   ```js
   const wss = new WebSocketServer({ noServer: true });
   const wsClients = new Set();
   wss.on('connection', (ws) => {
     console.log('[WebSocket] Client connected');
     wsClients.add(ws);
     ws.on('error', (err) => console.error('[WebSocket] Error:', err));
     ws.on('close', () => {
       console.log('[WebSocket] Client disconnected');
       wsClients.delete(ws);
     });
     ws.send(JSON.stringify({ event: 'connected', timestamp: new Date().toISOString() }));
   });
   ```
3. Create broadcast helper (after wss setup):
   ```js
   function broadcast(event, data) {
     const message = JSON.stringify({ event, data, timestamp: new Date().toISOString() });
     wsClients.forEach(client => {
       if (client.readyState === 1) {
         try {
           client.send(message);
         } catch (err) {
           console.error('[WebSocket] Broadcast error:', err);
         }
       }
     });
   }
   ```
4. Modify `startServer()` (line ~180) to handle HTTP upgrade:
   ```js
   const server = app.listen(port, () => {
     logger.info(`Server running on port ${port}`);
   });
   server.on('upgrade', (req, socket, head) => {
     if (req.url === '/ws') {
       wss.handleUpgrade(req, socket, head, (ws) => {
         wss.emit('connection', ws, req);
       });
     } else {
       socket.destroy();
     }
   });
   ```
5. Add broadcast calls to existing endpoints:
   - Line ~145 (PATCH /api/tasks/:id) after `updateTaskStatus()`: `broadcast('task_updated', { id: req.params.id, status: req.body.status });`
   - Line ~160 (PATCH /api/agents/:id/status) after `updateAgentStatus()`: `broadcast('agent_status_changed', { id: req.params.id, status: req.body.status });`
   - After any `logActivity()` call: `broadcast('activity_logged', { activity });`
   - After any `logCost()` call: `broadcast('cost_updated', { cost });`

