   import ReconnectingWebSocket from 'reconnecting-websocket';
   const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
   const wsUrl = `${wsProtocol}//${window.location.host}/ws`;
   export const ws = new ReconnectingWebSocket(wsUrl, [], {
     connectionTimeout: 5000,
     maxRetries: 10,
     debug: import.meta.env.DEV,
   });
   ws.addEventListener('open', () => console.log('[WS] Connected'));
   ws.addEventListener('close', () => console.log('[WS] Disconnected'));
   ws.addEventListener('error', (err) => console.error('[WS] Error:', err));
   ```
2. Create message handler (export for use in components):
   ```ts
   export function setupWebSocketHandlers(queryClient: QueryClient) {
     ws.addEventListener('message', (event) => {
       try {
         const { event: eventType, data } = JSON.parse(event.data);
         if (['task_updated', 'agent_status_changed', 'activity_logged', 'cost_updated'].includes(eventType)) {
           queryClient.invalidateQueries({ queryKey: ['dashboard'] });
         }
       } catch (err) {
         console.error('[WS] Parse error:', err);
       }
     });
   }
   ```

