1. Add bulk update endpoint (after line ~145):
   ```js
   app.patch('/api/tasks/bulk', async (req, res) => {
     try {
       const { taskIds, updates } = req.body;
       if (!Array.isArray(taskIds) || !updates) {
         return res.status(400).json({ error: 'Invalid request' });
       }
       for (const id of taskIds) {
         if (updates.status) db.updateTaskStatus(id, updates.status);
         if (updates.assignee_id) db.assignTask(id, updates.assignee_id);
         if (updates.priority) {
           db.getDb().prepare('UPDATE tasks SET priority = ? WHERE id = ?').run(updates.priority, id);
         }
       }
       broadcast('tasks_bulk_updated', { taskIds, updates });
       res.json({ success: true, updated: taskIds.length });
     } catch (error) {
       res.status(500).json({ error: error.message });
     }
   });
   ```
2. Add task deletion endpoint (after bulk endpoint):
   ```js
   app.delete('/api/tasks/:id', (req, res) => {
     try {
       db.getDb().prepare('DELETE FROM tasks WHERE id = ?').run(req.params.id);
       broadcast('task_deleted', { id: req.params.id });
       res.json({ success: true });
     } catch (error) {
       res.status(500).json({ error: error.message });
     }
   });
   ```

