```tsx
import { useState, useMemo, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import ReactFlow, { Controls, Background, MiniMap } from 'reactflow';
import { DragDropContext, Droppable, Draggable } from 'react-beautiful-dnd';
import { format, startOfDay, endOfDay } from 'date-fns';
import { api } from '../api';
import 'reactflow/dist/style.css';

interface Filters {
  priority: 'all' | 'high' | 'medium' | 'low';
  status: 'all' | 'pending' | 'in_progress' | 'done' | 'failed';
  assignee: string; // 'all' or agent_id
  dateRange: { start: string | null; end: string | null };
}

export default function Tasks({ companyId }: { companyId: string }) {
  const queryClient = useQueryClient();
  const [filters, setFilters] = useState<Filters>({
    priority: 'all',
    status: 'all',
    assignee: 'all',
    dateRange: { start: null, end: null },
  });
  const [selectedTasks, setSelectedTasks] = useState<Set<string>>(new Set());
  const [viewMode, setViewMode] = useState<'list' | 'graph' | 'timeline'>('list');

  // Load filters from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('taskFilters');
    if (saved) setFilters(JSON.parse(saved));
  }, []);

  // Persist filters to localStorage
  useEffect(() => {
    localStorage.setItem('taskFilters', JSON.stringify(filters));
  }, [filters]);

  const { data: tasks = [], isLoading } = useQuery({
    queryKey: ['tasks', companyId],
    queryFn: async () => {
      const res = await fetch(`/api/companies/${companyId}/tasks`);
      return res.json();
    },
  });

  const { data: agents = [] } = useQuery({
    queryKey: ['agents', companyId],
    queryFn: async () => {
      const res = await fetch(`/api/companies/${companyId}/agents`);
      return res.json();
    },
  });

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      if (filters.priority !== 'all' && t.priority !== filters.priority) return false;
      if (filters.status !== 'all' && t.status !== filters.status) return false;
      if (filters.assignee !== 'all' && t.assignee_id !== filters.assignee) return false;
      if (filters.dateRange.start) {
        const taskDate = new Date(t.created_at);
        if (taskDate < startOfDay(new Date(filters.dateRange.start))) return false;
      }
      if (filters.dateRange.end) {
        const taskDate = new Date(t.created_at);
        if (taskDate > endOfDay(new Date(filters.dateRange.end))) return false;
      }
      return true;
    });
  }, [tasks, filters]);

  const bulkUpdateMutation = useMutation({
    mutationFn: async (updates: any) => {
      const res = await fetch('/api/tasks/bulk', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ taskIds: Array.from(selectedTasks), updates }),
      });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries(['tasks']);
      setSelectedTasks(new Set());
    },
  });

  const graphData = useMemo(() => {
    const nodes = filteredTasks.map((t, idx) => ({
      id: t.id,
      data: { label: `${t.title} (${t.status})` },
      position: { x: (idx % 5) * 200, y: Math.floor(idx / 5) * 100 },
    }));
    const edges = filteredTasks
      .filter(t => t.parent_id && filteredTasks.find(p => p.id === t.parent_id))
      .map(t => ({
        id: `${t.parent_id}-${t.id}`,
        source: t.parent_id,
        target: t.id,
        animated: true,
      }));
    return { nodes, edges };
  }, [filteredTasks]);

  const timelineData = useMemo(() => {
    return filteredTasks.map(t => ({
      task: t,
      startDate: new Date(t.created_at),
      endDate: t.completed_at ? new Date(t.completed_at) : new Date(),
    }));
  }, [filteredTasks]);

  const handleDragEnd = (result: any) => {
    if (!result.destination) return;
    const items = Array.from(filteredTasks);
    const [reordered] = items.splice(result.source.index, 1);
    items.splice(result.destination.index, 0, reordered);
    // Update priorities based on new order (optional enhancement)
  };

  return (
    <div className="p-6">
      {/* Filter bar */}
      <div className="mb-4 flex gap-4 flex-wrap">
        <select value={filters.priority} onChange={e => setFilters(f => ({ ...f, priority: e.target.value as any }))}>
          <option value="all">All Priorities</option>
          <option value="high">High</option>
          <option value="medium">Medium</option>
          <option value="low">Low</option>
        </select>
        <select value={filters.status} onChange={e => setFilters(f => ({ ...f, status: e.target.value as any }))}>
          <option value="all">All Statuses</option>
          <option value="pending">Pending</option>
          <option value="in_progress">In Progress</option>
          <option value="done">Done</option>
          <option value="failed">Failed</option>
        </select>
        <select value={filters.assignee} onChange={e => setFilters(f => ({ ...f, assignee: e.target.value }))}>
          <option value="all">All Agents</option>
          {agents.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
        </select>
        <input type="date" value={filters.dateRange.start || ''} onChange={e => setFilters(f => ({ ...f, dateRange: { ...f.dateRange, start: e.target.value } }))} />
        <input type="date" value={filters.dateRange.end || ''} onChange={e => setFilters(f => ({ ...f, dateRange: { ...f.dateRange, end: e.target.value } }))} />
      </div>

      {/* Bulk actions */}
      {selectedTasks.size > 0 && (
        <div className="mb-4 flex gap-2">
          <button onClick={() => bulkUpdateMutation.mutate({ status: 'done' })}>Mark Done</button>
          <button onClick={() => bulkUpdateMutation.mutate({ status: 'failed' })}>Mark Failed</button>
          <button onClick={() => setSelectedTasks(new Set())}>Clear Selection ({selectedTasks.size})</button>
        </div>
      )}

      {/* View mode toggle */}
      <div className="mb-4 flex gap-2">
        <button onClick={() => setViewMode('list')}>List</button>
        <button onClick={() => setViewMode('graph')}>Graph</button>
        <button onClick={() => setViewMode('timeline')}>Timeline</button>
      </div>

      {/* Views */}
      {viewMode === 'list' && (
        <DragDropContext onDragEnd={handleDragEnd}>
          <Droppable droppableId="tasks">
            {(provided) => (
              <div {...provided.droppableProps} ref={provided.innerRef}>
                {filteredTasks.map((task, idx) => (
                  <Draggable key={task.id} draggableId={task.id} index={idx}>
                    {(provided) => (
                      <div
                        ref={provided.innerRef}
                        {...provided.draggableProps}
                        {...provided.dragHandleProps}
                        className="p-4 mb-2 bg-zinc-800 rounded flex items-center gap-4"
                      >
                        <input
                          type="checkbox"
                          checked={selectedTasks.has(task.id)}
                          onChange={(e) => {
                            const updated = new Set(selectedTasks);
                            e.target.checked ? updated.add(task.id) : updated.delete(task.id);
                            setSelectedTasks(updated);
                          }}
                        />
                        <div className="flex-1">
                          <div className="font-bold">{task.title}</div>
                          <div className="text-sm text-zinc-400">{task.status} • {task.priority}</div>
                        </div>
                      </div>
                    )}
                  </Draggable>
                ))}
                {provided.placeholder}
              </div>
            )}
          </Droppable>
        </DragDropContext>
      )}

      {viewMode === 'graph' && (
        <div className="h-[600px] border border-zinc-800 rounded">
          <ReactFlow nodes={graphData.nodes} edges={graphData.edges}>
            <Controls />
            <Background />
            <MiniMap />
          </ReactFlow>
        </div>
      )}

      {viewMode === 'timeline' && (
        <div className="space-y-2">
          {timelineData.map(({ task, startDate, endDate }) => (
            <div key={task.id} className="flex items-center gap-4">
              <div className="w-32 text-sm">{format(startDate, 'MMM d')}</div>
              <div className="flex-1 bg-zinc-800 p-2 rounded">{task.title}</div>
              <div className="w-32 text-sm text-right">{format(endDate, 'MMM d')}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
```

