```tsx
import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  LineChart, Line, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';

const COLORS = ['#f59e0b', '#3b82f6', '#10b981', '#ef4444', '#8b5cf6'];

export default function Costs({ companyId }: { companyId: string }) {
  const { data, isLoading } = useQuery({
    queryKey: ['costs', companyId],
    queryFn: async () => {
      const res = await fetch(`/api/companies/${companyId}/costs`);
      if (!res.ok) throw new Error('Failed to fetch costs');
      return res.json();
    },
  });

  // Transform data for line chart (cost over time)
  const costOverTime = useMemo(() => {
    if (!data?.recent) return [];
    const grouped = data.recent.reduce((acc, entry) => {
      const date = entry.created_at.split('T')[0];
      acc[date] = (acc[date] || 0) + parseFloat(entry.cost_usd);
      return acc;
    }, {} as Record<string, number>);
    return Object.entries(grouped)
      .map(([date, cost]) => ({ date, cost: parseFloat(cost.toFixed(4)) }))
      .sort((a, b) => a.date.localeCompare(b.date));
  }, [data]);

  // Cost by agent (already aggregated in data.summary)
  const costByAgent = useMemo(() => {
    if (!data?.summary) return [];
    return data.summary
      .map(s => ({
        agent: s.agent_name,
        cost: parseFloat(s.total_cost_usd.toFixed(4)),
      }))
      .sort((a, b) => b.cost - a.cost);
  }, [data]);

  // Token usage breakdown
  const tokenData = useMemo(() => {
    if (!data?.summary) return [];
    return data.summary.map(s => ({
      agent: s.agent_name,
      input: s.total_input_tokens,
      output: s.total_output_tokens,
      cache: s.total_cache_read_tokens || 0,
    }));
  }, [data]);

  // Projected monthly burn
  const projectedBurn = useMemo(() => {
    if (!data?.totals) return '0.00';
    const now = new Date();
    const daysSoFar = now.getDate();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const dailyAvg = data.totals.total_cost_usd / daysSoFar;
    return (dailyAvg * daysInMonth).toFixed(2);
  }, [data]);

  // CSV export handler
  const exportCSV = () => {
    if (!data?.recent) return;
    const headers = ['Date', 'Agent', 'Task ID', 'Input Tokens', 'Output Tokens', 'Cache Read Tokens', 'Cost USD'];
    const rows = data.recent.map(r => [
      r.created_at,
      r.agent_name || 'Unknown',
      r.task_id || 'N/A',
      r.input_tokens,
      r.output_tokens,
      r.cache_read_tokens || 0,
      r.cost_usd,
    ]);
    const csv = [headers, ...rows].map(row => row.join(',')).join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `costs-${companyId}-${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  if (isLoading) return <div className="p-6">Loading costs...</div>;
  if (!data) return <div className="p-6">No cost data available</div>;

  return (
    <div className="p-6 space-y-8">
      {/* Header */}
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold">Cost Analytics</h1>
        <button
          onClick={exportCSV}
          className="px-4 py-2 bg-amber-600 hover:bg-amber-700 rounded text-sm font-medium"
        >
          Export CSV
        </button>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-zinc-800 p-4 rounded">
          <div className="text-sm text-zinc-400">Total Spend</div>
          <div className="text-2xl font-bold text-amber-400">${data.totals.total_cost_usd.toFixed(4)}</div>
        </div>
        <div className="bg-zinc-800 p-4 rounded">
          <div className="text-sm text-zinc-400">Projected Monthly</div>
          <div className="text-2xl font-bold text-blue-400">${projectedBurn}</div>
        </div>
        <div className="bg-zinc-800 p-4 rounded">
          <div className="text-sm text-zinc-400">Total Tokens</div>
          <div className="text-2xl font-bold text-emerald-400">
            {(data.totals.total_input_tokens + data.totals.total_output_tokens).toLocaleString()}
          </div>
        </div>
      </div>

      {/* Line Chart - Cost Over Time */}
      <div className="bg-zinc-800 p-6 rounded">
        <h2 className="text-lg font-semibold mb-4">Spend Trend (Last 30 Days)</h2>
        <ResponsiveContainer width="100%" height={300}>
          <LineChart data={costOverTime}>
            <CartesianGrid strokeDasharray="3 3" stroke="#3f3f46" />
            <XAxis dataKey="date" stroke="#a1a1aa" />
            <YAxis stroke="#a1a1aa" />
            <Tooltip contentStyle={{ backgroundColor: '#27272a', border: 'none' }} />
            <Line type="monotone" dataKey="cost" stroke="#f59e0b" strokeWidth={2} dot={{ fill: '#f59e0b' }} />
          </LineChart>
        </ResponsiveContainer>
      </div>

      {/* Bar Chart - Cost by Agent */}
      <div className="bg-zinc-800 p-6 rounded">
        <h2 className="text-lg font-semibold mb-4">Cost by Agent</h2>
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={costByAgent}>
            <CartesianGrid strokeDasharray="3 3" stroke="#3f3f46" />
            <XAxis dataKey="agent" stroke="#a1a1aa" />
            <YAxis stroke="#a1a1aa" />
            <Tooltip contentStyle={{ backgroundColor: '#27272a', border: 'none' }} />
            <Bar dataKey="cost" fill="#f59e0b" />
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Pie Chart - Cost Distribution */}
      <div className="bg-zinc-800 p-6 rounded">
        <h2 className="text-lg font-semibold mb-4">Cost Distribution</h2>
        <ResponsiveContainer width="100%" height={300}>
          <PieChart>
            <Pie
              data={costByAgent}
              dataKey="cost"
              nameKey="agent"
              cx="50%"
              cy="50%"
              outerRadius={100}
              label={(entry) => `${entry.agent}: $${entry.cost}`}
            >
              {costByAgent.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
              ))}
            </Pie>
            <Tooltip contentStyle={{ backgroundColor: '#27272a', border: 'none' }} />
          </PieChart>
        </ResponsiveContainer>
      </div>

      {/* Token Breakdown */}
      <div className="bg-zinc-800 p-6 rounded">
        <h2 className="text-lg font-semibold mb-4">Token Usage Breakdown</h2>
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={tokenData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#3f3f46" />
            <XAxis dataKey="agent" stroke="#a1a1aa" />
            <YAxis stroke="#a1a1aa" />
            <Tooltip contentStyle={{ backgroundColor: '#27272a', border: 'none' }} />
            <Legend />
            <Bar dataKey="input" stackId="a" fill="#3b82f6" name="Input Tokens" />
            <Bar dataKey="output" stackId="a" fill="#10b981" name="Output Tokens" />
            <Bar dataKey="cache" stackId="a" fill="#8b5cf6" name="Cache Tokens" />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}
```

